import type CatalogFootprintLayer from "../../layers/catalog/CatalogFootprintLayer.js";
import type FeatureLikeLayerView from "./FeatureLikeLayerView.js";

/**
 * Represents the [LayerView](https://developers.arcgis.com/javascript/latest/references/core/views/layers/LayerView/) of a [CatalogLayer's footprintLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/CatalogLayer/#footprintLayer)
 * after the CatalogLayer has been added to a [Map](https://developers.arcgis.com/javascript/latest/references/core/Map/) in either a [MapView](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/), [Map component](https://developers.arcgis.com/javascript/latest/references/map-components/components/arcgis-map/),
 * [SceneView](https://developers.arcgis.com/javascript/latest/references/core/views/SceneView/) or [Scene component](https://developers.arcgis.com/javascript/latest/references/map-components/components/arcgis-scene/).
 *
 * @since 4.30
 * @see [CatalogFootprintLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/catalog/CatalogFootprintLayer/)
 * @see [CatalogLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/CatalogLayer/)
 */
export default abstract class CatalogFootprintLayerView extends FeatureLikeLayerView {
  /** The layer being viewed. */
  get layer(): CatalogFootprintLayer;
}